// Enhance prompt using template rules — no external API needed
const body = $input.first().json.body;
const prompt = body.prompt || '';
const style = body.style || 'realistic';
const mode = body.mode || 'none';
const angle = body.angle || 'none';

if (!prompt.trim()) {
  return [{ json: { success: false, error: 'Prompt is empty' } }];
}

const styleGuides = {
  realistic: {
    prefix: '',
    details: ['Shot with a professional DSLR camera','Natural lighting with soft diffusion','Sharp focus with bokeh background','Rich color grading with cinematic tones','High dynamic range','Photorealistic rendering, 8K resolution'],
    suffix: 'Ultra-detailed, photorealistic, professional photography, masterful composition'
  },
  anime: {
    prefix: 'Anime-style illustration. ',
    details: ['Clean line art with cel shading','Vibrant saturated colors','Dynamic pose and expressive features','Detailed background with depth layers','Sparkle and light effects','Studio quality anime production art'],
    suffix: 'High-quality anime art, detailed illustration, trending on Pixiv, by top anime artists'
  },
  illustration: {
    prefix: 'Digital illustration. ',
    details: ['Concept art quality with painterly strokes','Dramatic lighting and atmosphere','Rich texture and material details','Cinematic composition with strong focal point','Professional color palette','ArtStation quality, trending concept art'],
    suffix: 'Award-winning illustration, concept art, digital painting, masterpiece quality'
  }
};

const modeGuides = {
  none: { prefix: '', details: [], suffix: '' },
  infographic: { prefix: 'Infographic design layout. ', details: ['Clean data visualization with charts and icons','Organized information hierarchy','Modern flat design with bold typography','Color-coded categories','Professional business style'], suffix: 'Infographic poster, data-driven design, clean layout' },
  'remove-bg': { prefix: 'Subject isolated on pure white background. ', details: ['Clean cutout with no background','Pure white seamless backdrop','Subject perfectly centered','Studio product lighting','No background shadows'], suffix: 'Isolated subject, white background, product photography' },
  storyboard: { prefix: 'Storyboard panel sequence. ', details: ['Comic multi-panel grid layout','Sequential storytelling frames','Clear panel borders','Action arrows and movement indicators','Consistent character design'], suffix: 'Storyboard art, sequential panels, cinematic frames' }
};

const angleGuides = {
  none: '',
  front: 'Front-facing shot, eye-level direct view, symmetrical composition. ',
  wide: 'Extreme wide-angle shot, establishing shot, panoramic view. ',
  shoulder: 'Over-the-shoulder shot, depth perspective, cinematic framing. ',
  low: 'Low-angle shot, dramatic heroic perspective, subject appears powerful. ',
  high: "High-angle bird's-eye view, overhead perspective, top-down composition. ",
  behind: 'Rear view from behind the subject, atmospheric depth, mysterious mood. '
};

const guide = styleGuides[style] || styleGuides.realistic;
const modeGuide = modeGuides[mode] || modeGuides.none;
const anglePrefix = angleGuides[angle] || '';

const mainPrompt = guide.prefix + modeGuide.prefix + anglePrefix + prompt.charAt(0).toUpperCase() + prompt.slice(1) + '.';
const allDetails = [...guide.details, ...modeGuide.details];
const combinedSuffix = [guide.suffix, modeGuide.suffix].filter(Boolean).join('. ');

const enhanced = [mainPrompt, '', 'Visual Details:', ...allDetails.map(d => `- ${d}`), '', combinedSuffix].join('\n');

return [{ json: { success: true, enhanced } }];

const data = $input.first().json;
const candidates = data.candidates || [];
let resultText = '';
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];
  for (const part of parts) {
    if (part.text) resultText += part.text;
  }
}
if (resultText.trim()) {
  let clean = resultText.trim();
  if (clean.startsWith('"') && clean.endsWith('"')) clean = clean.slice(1, -1);
  if (clean.startsWith('```') && clean.endsWith('```')) clean = clean.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  return [{ json: { success: true, adaptedPrompt: clean } }];
}
return [{ json: { success: false, error: 'Could not analyze reference image' } }];
